import React, { Component } from "react";
import styled, { css } from "styled-components";
import styles from "../../styles/styles";

import WebPage from "../../components/webPage/WebPage";
import PageArticle from "../../components/pageArticle/PageArticle";
import Emoji from "../../components/emoji/Emoji";

// Inspiration: https://www.w3schools.com/howto/howto_css_flip_card.asp

const flipped = css`
  transform: rotateX(16deg) rotateY(-184deg);
`;

const notFlipped = css`
  transform: rotateX(16deg) rotateY(4deg);
`;

const normal = css`
  transform: rotateX(0deg) rotateY(0deg);
`;

const cardShadow = css`
  box-shadow: rgba(0, 0, 0, 0.024) 0px 0px 0px 1px,
    rgba(0, 0, 0, 0.05) 0px 1px 0px 0px, rgba(0, 0, 0, 0.03) 0px 0px 8px 0px,
    rgba(0, 0, 0, 0.1) 0px 20px 30px 0px;
`;

const FlipCard = styled.div`
  &.size {
    background-color: transparent;
    width: 8.5cm;
    height: 5.5cm;
    perspective: 800px;
  }

  &.content {
    position: relative;
    width: 100%;
    height: 100%;
    transition: transform 1s;
    transform-style: preserve-3d;
    ${cardShadow}
  }

  &.size .content {
    ${(props) => (props.flipped ? `${flipped}` : `${notFlipped}`)}
  }

  &.size:hover .content {
    ${normal}
  }

  &.front,
  .back {
    position: absolute;
    width: 100%;
    height: 100%;
    /* -webkit-backface-visibility: hidden; */
    backface-visibility: hidden;
  }

  &.front,
  .back,
  .content {
    border-radius: 4px;
  }

  &.front {
    background-color: var(--hard-white);
  }

  &.back {
    transform: rotateY(180deg);
    background-color: var(--neon-yellow);
  }
`;

class BusinessCard extends Component {
  constructor() {
    super();
  }

  render() {
    return (
      <FlipCard className="size" flipped={this.props.flipped}>
        <FlipCard className="content" flipped={this.props.flipped}>
          <FlipCard className="front">
            <h1>Niklas Buhl</h1>
            <p>Tel:</p>
            <p>Mail:</p>
          </FlipCard>

          <FlipCard className="back">
            <h1>Billede</h1>
          </FlipCard>
        </FlipCard>
      </FlipCard>
    );
  }
}

const Element = styled.div`
  display: flex;
  /* flex-grow: 1; */
`;

class DevContactPage extends Component {
  constructor() {
    super();

    this.state = {
      flipBusinessCard: false,
    };

    this.flipBusinessCard = this.flipBusinessCard.bind(this);
  }

  flipBusinessCard() {
    console.log("Flip business card.");

    this.setState((prevState) => ({
      flipBusinessCard: !prevState.flipBusinessCard,
    }));
  }

  render() {
    return (
      <WebPage>
        <PageArticle
          innerStyle={`
            flex-direction: column;
          `}
        >
          <Element
            css={`
              height: 25%;
            `}
          >
            <h1>Contact</h1>
          </Element>

          <Element css={"height: 50%;"}>
            <Element
              css={`
                width: 25%;
              `}
            />

            <Element
              css={`
                width: 50%;
                ${styles.position.centerCenter}
              `}
            >
              <BusinessCard flipped={this.state.flipBusinessCard} />
            </Element>

            <Element
              css={`
                width: 25%;
                ${styles.position.centerCenter}
              `}
            >
              <button
                type="button"
                onClick={this.flipBusinessCard}
                style={{ height: "48px", widht: "96px" }}
              >
                Flip
              </button>
            </Element>
          </Element>

          <Element
            css={`
              height: 25%;
              ${styles.position.centerCenter}
            `}
          >
            <a href="../Niklas%20Buhl%20vCard.vcf">
              <h3
                css={`
                  color: var(--gray);
                  ${styles.shadow.hollow}
                `}
              >
                Download vCard
              </h3>
            </a>
            <p className="code">Add me to your contacts</p>
          </Element>
        </PageArticle>
      </WebPage>
    );
  }
}

export default DevContactPage;

